 17â†’function preferredMimeType(): string {
 18â†’  if (typeof MediaRecorder !== 'undefined') {
 19â†’    if (MediaRecorder.isTypeSupported('audio/webm')) return 'audio/webm'
 20â†’    if (MediaRecorder.isTypeSupported('audio/mp4')) return 'audio/mp4'
 21â†’  }
 22â†’  return ''
 23â†’}
