 37â†’    if (intervalRef.current !== null) {
 38â†’      clearInterval(intervalRef.current)
 39â†’      intervalRef.current = null
 40â†’    }
 41â†’  }, [])
 42â†’
 43â†’  const releaseStream = useCallback(() => {
 44â†’    if (streamRef.current) {
 45â†’      streamRef.current.getTracks().forEach((t) => t.stop())
 46â†’      streamRef.current = null
 47â†’    }
 48â†’  }, [])
 49â†’
 50â†’  const start = useCallback(async () => {
 51â†’    setError(null)
 52â†’    setAudioBlob(null)
 53â†’    setDuration(0)
 54â†’    chunksRef.current = []
 55â†’
 56â†’    try {
 57â†’      const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
 58â†’      streamRef.current = stream
 59â†’
 60â†’      const mimeType = preferredMimeType()
 61â†’      const recorder = mimeType
 62â†’        ? new MediaRecorder(stream, { mimeType })
 63â†’        : new MediaRecorder(stream)
 64â†’
 65â†’      recorder.ondataavailable = (e) => {
 66â†’        if (e.data.size > 0) {
 67â†’          chunksRef.current.push(e.data)
 68â†’        }
 69â†’      }
 70â†’
 71â†’      recorder.onstop = () => {
 72â†’        const type = recorder.mimeType || 'audio/webm'
 73â†’        const blob = new Blob(chunksRef.current, { type })
 74â†’        setAudioBlob(blob)
 75â†’        setStatus('stopped')
 76â†’        clearTimer()
 77â†’        releaseStream()
 78â†’      }
 79â†’
 80â†’      recorderRef.current = recorder
 81â†’      recorder.start()
 82â†’      setStatus('recording')
 83â†’
 84â†’      intervalRef.current = setInterval(() => {
 85â†’        setDuration((d) => d + 1)
 86â†’      }, 1000)
 87â†’    } catch (err) {
 88â†’      releaseStream()
 89â†’      if (err instanceof DOMException) {
 90â†’        if (err.name === 'NotAllowedError') {
 91â†’          setError('Microphone permission denied')
 92â†’        } else if (err.name === 'NotFoundError') {
 93â†’          setError('No microphone found')
 94â†’        } else {
 95â†’          setError(`Microphone error: ${err.message}`)
 96â†’        }
 97â†’      } else {
 98â†’        setError('Failed to start recording')
 99â†’      }
100â†’    }
101â†’  }, [clearTimer, releaseStream])
102â†’
103â†’  const stop = useCallback(() => {
104â†’    if (recorderRef.current && recorderRef.current.state !== 'inactive') {
105â†’      recorderRef.current.stop()
106â†’    }
107â†’  }, [])
108â†’
109â†’  const pause = useCallback(() => {
110â†’    if (recorderRef.current && recorderRef.current.state === 'recording') {
111â†’      recorderRef.current.pause()
112â†’      clearTimer()
113â†’      setStatus('paused')
114â†’    }
115â†’  }, [clearTimer])
116â†’
117â†’  const resume = useCallback(() => {
118â†’    if (recorderRef.current && recorderRef.current.state === 'paused') {
119â†’      recorderRef.current.resume()
120â†’      setStatus('recording')
121â†’      intervalRef.current = setInterval(() => {
122â†’        setDuration((d) => d + 1)
123â†’      }, 1000)
124â†’    }
125â†’  }, [])
126â†’
127â†’  const reset = useCallback(() => {
128â†’    if (recorderRef.current && recorderRef.current.state !== 'inactive') {
129â†’      recorderRef.current.stop()
130â†’    }
131â†’    clearTimer()
132â†’    releaseStream()
133â†’    recorderRef.current = null
134â†’    chunksRef.current = []
135â†’    setAudioBlob(null)
136â†’    setDuration(0)
137â†’    setError(null)
138â†’    setStatus('idle')
139â†’  }, [clearTimer, releaseStream])
140â†’
141â†’  useEffect(() => {
142â†’    return () => {
143â†’      clearTimer()
144â†’      releaseStream()
145â†’      if (recorderRef.current && recorderRef.current.state !== 'inactive') {
146â†’        recorderRef.current.stop()
147â†’      }
148â†’    }
149â†’  }, [clearTimer, releaseStream])
150â†’
151â†’  return { status, audioBlob, duration, error, start, stop, pause, resume, reset }
152â†’}
