import { Link } from 'react-router-dom'
import { Card, Text, Group, Badge, Box } from '@mantine/core'

interface ItemCardItem {
  id: string
  type: string
  title: string | null
  contentText: string | null
  tags: string[]
  source: string
  sourceUrl: string | null
  capturedAt: string
}

interface ItemCardProps {
  item: ItemCardItem
  compact?: boolean
}

const TYPE_COLORS: Record<string, string> = {
  BOOKMARK: 'blue',
  TEXT_NOTE: 'green',
  VOICE_NOTE: 'orange',
  DRIVE_DOC: 'violet',
  HIGHLIGHT: 'yellow',
  FILE: 'gray',
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString()
}

function formatType(type: string): string {
  return type.replace(/_/g, ' ').toLowerCase()
}

export function ItemCard({ item, compact }: ItemCardProps) {
  return (
    <Card
      component={Link}
      to={`/items/${item.id}`}
      shadow="xs"
      padding={compact ? 'sm' : 'md'}
      radius="md"
      withBorder
      style={{ textDecoration: 'none', color: 'inherit' }}
    >
      <Group justify="space-between" mb={compact ? 4 : 'xs'}>
        <Text fw={600} fz={compact ? 'sm' : 'md'} lineClamp={1} style={{ flex: 1 }}>
          {item.title ?? 'Untitled'}
        </Text>
        <Badge size="sm" variant="light" color={TYPE_COLORS[item.type] ?? 'gray'}>
          {formatType(item.type)}
        </Badge>
      </Group>
      {!compact && item.contentText && (
        <Text fz="sm" c="dimmed" lineClamp={2}>
          {item.contentText}
        </Text>
      )}
      <Group gap="xs" mt={compact ? 4 : 'xs'}>
        {item.tags.slice(0, compact ? 3 : 5).map((tag) => (
          <Badge key={tag} size="xs" variant="outline">
            {tag}
          </Badge>
        ))}
        {item.tags.length > (compact ? 3 : 5) && (
          <Box component="span">
            <Text fz="xs" c="dimmed">
              +{item.tags.length - (compact ? 3 : 5)}
            </Text>
          </Box>
        )}
        <Text fz="xs" c="dimmed" ml="auto">
          {formatDate(item.capturedAt)}
        </Text>
      </Group>
    </Card>
  )
}

