import { test, expect, type Page } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'

async function login(page: Page) {
  await page.goto('/login')
  await page.getByLabel('Email').fill('ketan@example.com')
  await page.getByLabel('Password').fill('testpassword123')
  await page.getByRole('button', { name: 'Login' }).click()
  await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()
}

test.describe('Voice Demo', () => {
  test('Voice capture UI is accessible', async ({ page }) => {
    await login(page)

    // Navigate to capture page and select Voice tab
    await page.goto('/capture')
    await page.getByRole('tab', { name: 'Voice' }).click()

    // Verify recording UI is visible
    await expect(page.getByLabel('Start recording')).toBeVisible()
    await expect(page.getByText('Tap to record')).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Voice notes appear in browse', async ({ page }) => {
    await login(page)

    // Navigate to browse and filter to voice notes
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')

    // Click the Voice type filter chip
    await page.getByText('Voice', { exact: true }).click()
    await page.waitForLoadState('networkidle')

    // Verify seeded voice notes are visible
    await expect(page.getByText('Q2 Planning Meeting Recap')).toBeVisible()
    await expect(
      page.getByText('Book Recommendation: Designing Data-Intensive Applications')
    ).toBeVisible()

    // Verify voice note type badge
    await expect(page.getByText('voice note').first()).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Voice note detail page', async ({ page }) => {
    await login(page)

    // Browse voice notes
    await page.goto('/browse')
    await page.waitForLoadState('networkidle')
    await page.getByText('Voice', { exact: true }).click()
    await page.waitForLoadState('networkidle')

    // Click into the first voice note
    await page.getByText('Q2 Planning Meeting Recap').click()

    // Verify detail page loaded
    await expect(page).toHaveURL(/\/items\//)
    await expect(page.getByText('Q2 Planning Meeting Recap')).toBeVisible()
    await expect(page.getByText('voice note')).toBeVisible()

    if (isManual) await page.pause()
  })
})

